def titleScreen():

    global level, fight_start_time, health, max_health, difficulty_mode
    start_time = pygame.time.get_ticks()
    # unused: has_punched = False
    

    boot_sequence = [
        "> INITIALIZING SYSTEM...",
        "> LOADING DEMO...",
        "> ACCESSING OMEGA_DRIVE...",
        "> LOADING WEAPONS...",
        "> ACCESSING USER_DATA...",    
        "> HIJACKING SAVE_FILE...",
        "> COMPLETE."
    ]

    while level == 0:
        clock.tick(60)
        screen.fill(BLACK)
        now = pygame.time.get_ticks()
        elapsed = (now - start_time) / 1000
        
        # --- 1. Terminal Boot---
        if elapsed < 5:
            for i, line in enumerate(boot_sequence):
                if elapsed > i * 0.7:
                    msg = ui_font.render(line, True, (0, 255, 0))
                    screen.blit(msg, (50, 50 + (i * 30)))
        
        # --- 2. The Hijacked Save Box ---
        else:
            save_rect = pygame.Rect(screenWidth // 2 - 250, 180, 500, 160)
            pygame.draw.rect(screen, WHITE, save_rect, 3) # White border
            
            name_str = "Flowey"
            loc_str = "My World"
            prompt_str = "[ CLICK TO BEGIN ]" # Original prompt
            
            # --- 3. The Soul Punch / Cracks ---
            if elapsed > 7:
                
                # Flickering Gray/Color Rays
                for _ in range(12):
                    # Randomly flicker between Gray and Soul Colors
                    color = random.choice([GRAY, CYAN, ORANGE, BLUE, PURPLE, GREEN, YELLOW])
                    start_pos = (save_rect.centerx - 100, save_rect.y + 40)
                    end_pos = (random.randint(0, 800), random.randint(0, 600))
                    pygame.draw.line(screen, color, start_pos, end_pos, 1)

                name_str = "".join(random.choice("&$%#!?██") for _ in range(6))
                prompt_str = "[ PRESS SPACE TO CONTINUE ]" 
                easy_prompt = ui_font.render("[ E: SUPER EASY MODE ]", True, (0, 200, 0)) 
                norm_prompt = ui_font.render("[ SPACE: NORMAL ]", True, (255, 255, 255))
                hard_prompt = ui_font.render("[ H: HARD MODE ]", True, (255, 0, 0))
            
                screen.blit(norm_prompt, (screenWidth // 2 - 100, 560))
                screen.blit(hard_prompt, (600, 560))
                # Place in bottom-left corner
                screen.blit(easy_prompt, (20, 560))
            if elapsed == 7:
                smash.play()
                # Screen Shake
                save_rect.x += random.randint(-4, 4)
            
            # Draw Save Content
            screen.blit(ui_font.render(name_str, True, WHITE), (save_rect.x + 30, 210))
            screen.blit(ui_font.render("LV 9999", True, WHITE), (save_rect.x + 220, 210))
            screen.blit(ui_font.render(loc_str, True, WHITE), (save_rect.x + 30, 280))

            # Prompt Logic (Blinking)
            if int(now / 500) % 2 == 0:
                color = YELLOW if elapsed > 7 else WHITE
                prompt = ui_font.render(prompt_str, True, color)
                screen.blit(prompt, prompt.get_rect(center=(screenWidth // 2, 480)))


        # --- Input ---
        for event in pygame.event.get():
            if event.type == pygame.QUIT: pygame.quit(); sys.exit()
            
            if elapsed > 5: # Only allow input after boot
                # SPACE = NORMAL MODE
                if event.type == pygame.KEYDOWN and event.key == pygame.K_SPACE:
                    difficulty_mode = "normal"
                    health, max_health = 20, 20
                    
                    level = 1
                    fight_start_time = pygame.time.get_ticks()
                    pygame.mixer.stop()
                    play_Finale()
                # E = EASY MODE
                elif event.type == pygame.KEYDOWN and event.key == pygame.K_e:
                    difficulty_mode = "easy"
                    health, max_health = 40, 40
                    
                    level = 1
                    fight_start_time = pygame.time.get_ticks()
                    pygame.mixer.stop()
                    play_Finale()
                # H = HARD MODE
                elif event.type == pygame.KEYDOWN and event.key == pygame.K_h:
                    difficulty_mode = "hard"
                    health, max_health = 20, 20
                    
                    level = 1
                    fight_start_time = pygame.time.get_ticks()
                    pygame.mixer.stop()
                    play_Finale()
        pygame.display.flip()
