class Player(pygame.sprite.Sprite):
    """Player sprite with position properties"""
    
    def __init__(self, image):
        super().__init__()
        self.image = image
        self.rect = self.image.get_rect()
        self.rect.x = BORDER_LEFT + BORDER_WIDTH / 2 - self.rect.width / 2
        self.rect.y = BORDER_TOP + BORDER_HEIGHT / 2 - self.rect.height / 2 - 60
        self.is_invincible = False
        self.last_hit_time = 0
        self.INVINC_TIME = 1000  # 1 second of safety

    @property
    def x(self):
        return self.rect.x
    
    @x.setter
    def x(self, value):
        self.rect.x = value
    
    @property
    def y(self):
        return self.rect.y
    
    @y.setter
    def y(self, value):
        self.rect.y = value
    
    def updateInvis(self):
        current_time = pygame.time.get_ticks()
        
        # Check if invincibility should expire
        if self.is_invincible and current_time - self.last_hit_time > 1000:  # 1000ms = 1s
            self.is_invincible = False
    def draw(self, surface):
        current_time = pygame.time.get_ticks()
        show_heart = True

        if self.is_invincible:
            # Toggle visibility every 100ms
            # (current_time // 100) % 2 results in either 0 or 1
            if (current_time // 100) % 2 == 0:
                show_heart = False

        if show_heart:
            # Draw your sprite image
            surface.blit(self.image, self.rect) 
class GreenShield:
    def __init__(self, radius=45):
        self.radius = radius
        self.angle = 90
        self.rect = pygame.Rect(0, 0, 30, 30) # Collision hitbox
        self.width = 40  # Visual width
        self.height = 10 # Visual thickness

    def update(self, soul_rect, current_angle):
        self.angle = current_angle
        # Position shield in orbit around the soul
        rad = math.radians(self.angle)
        self.rect.centerx = soul_rect.centerx + self.radius * math.cos(rad)
        self.rect.centery = soul_rect.centery - self.radius * math.sin(rad)

    def draw(self, surface):
        # Create a surface for the shield to rotate it properly
        shield_surf = pygame.Surface((self.width, self.height), pygame.SRCALPHA)
        # Draw a "Cool" Neon Green Bar
        pygame.draw.rect(shield_surf, (0, 255, 0), (0, 0, self.width, self.height), border_radius=5)
        pygame.draw.rect(shield_surf, (200, 255, 200), (2, 2, self.width-4, self.height-4), border_radius=5) # Inner glow
        
        rotated_shield = pygame.transform.rotate(shield_surf, self.angle - 90)
        new_rect = rotated_shield.get_rect(center=self.rect.center)
        surface.blit(rotated_shield, new_rect.topleft)

