class HeartFragment:
    def __init__(self, x, y):
        self.x = x
        self.y = y
        # Give fragments random horizontal/vertical bursts
        self.vx = random.uniform(-1.5, 1.5)  #speed for velocity
        self.vy = random.uniform(-3.0, -9.0) # Initial jump up
        self.gravity = 0.25 # Gravity pull down

    def update(self):
        self.x += self.vx
        self.y += self.vy
        self.vy += self.gravity # Gravity makes them fall over time

    def draw(self, screen):
        # Draw a small 4x4 red square for the fragment
        pygame.draw.rect(screen, (255, 0, 0), (self.x, self.y, 4, 4))

