class EnemyBullet(pygame.sprite.Sprite):
    """Enemy bullets that wave back and forth while falling"""
    
    def __init__(self, x, y, speed=10):
        super().__init__()
        self.screen_height = screen.get_height()

        self.original_image = pygame.Surface((35, 20), pygame.SRCALPHA)
        self.original_image.fill(WHITE)
        pygame.draw.rect(self.original_image, RED_DARK, (0, 0, 35, 20), 3)

        self.image = self.original_image.copy()
        self.rect = self.image.get_rect(center=(x, y))

        self.speed = speed
        self.start_x = x
        self.time_elapsed = 0
        self.amplitude = 50 # how far left and right the bullet will wave
        self.frequency = 0.075 # how fast the bullet will wave
        self.angle = 0 # current rotation angle
        self.rotation_speed = random.randint(3, 7) # how fast the bullet will rotate

    def update(self): 
        self.rect.y += self.speed # move bullet down the screen
        self.time_elapsed += 1 # increment time for wave calculation
        current_center_x = self.start_x + self.amplitude * math.sin(self.frequency * self.time_elapsed) # calculate new x position for wave motion
        self.angle = (self.angle + self.rotation_speed) % 360 # continuously rotate the bullet
        self.image = pygame.transform.rotate(self.original_image, self.angle)  
        self.rect = self.image.get_rect(center=(current_center_x, self.rect.centery)) 

        if self.rect.top > 800: 
            self.kill()

class IntroNarrator:
    def __init__(self, font):
        self.font = font
        # Define the default messages
        self.messages = [
            (0, (0, 255, 255), "You feel the power of Patience coursing within you."),
            (3500, (255, 165, 0), "You feel the power of Bravery burning in your heart."),
            (7000, (0, 0, 255), "You feel the power of Integrity guiding your path."),
            (10500, (255, 0, 255), "You feel the power of Perseverance aiding your mind."),
            (14000, (0, 255, 0), "You feel the power of Kindness mending your soul."),
            (17500, (255, 255, 0), "You feel the power of Justice aiming for victory."),
            (21000, (255, 255, 255), "THEY ARE ALL WITH YOU!")
        ]
        self.char_index = 0
        self.last_char_time = 0
        self.current_msg_start_time = -1 # Track which message is currently typing

    def draw(self, screen, elapsed_ms):
        current_msg = None
        # Find which message to show based on time
        for start_time, color, text in self.messages:
            if elapsed_ms >= start_time:
                current_msg = (color, text, start_time)
        
        if current_msg:
            color, text, start_time = current_msg
            
            if self.current_msg_start_time != start_time:
                self.char_index = 0
                self.current_msg_start_time = start_time
                self.last_char_time = elapsed_ms

            if elapsed_ms - self.last_char_time > 30 and self.char_index < len(text):
                self.char_index += 1
                self.last_char_time = elapsed_ms

            # Render and blit
            rendered_text = self.font.render(text[:self.char_index], True, color)
            text_rect = rendered_text.get_rect(center=(screenWidth // 2, screenHeight // 2 + 100))
            screen.blit(rendered_text, text_rect)

    def reset(self):
        self.char_index = 0
        self.last_char_time = 0
        self.current_msg_start_time = -1 
class GameOverNarrator:
    def __init__(self, font):
        self.font = font
        self.char_index = 0
        self.last_char_time = 0
        self.text = "Stay determined..."

    def draw(self, screen, elapsed_ms, start_trigger_ms):
        # Only start typing once we've hit the trigger time
        if elapsed_ms < start_trigger_ms:
            return

        # Typewriter logic: 1 char every 60ms
        if elapsed_ms - self.last_char_time > 60 and self.char_index < len(self.text):
            self.char_index += 1
            self.last_char_time = elapsed_ms

        rendered = self.font.render(self.text[:self.char_index], True, (255, 255, 255))
        rect = rendered.get_rect(center=(screenWidth // 2, 450))
        screen.blit(rendered, rect)
class BossDialogue:
    def __init__(self, text_list, font):
        self.text_list = text_list
        self.font = font
        self.line_index = 0
        self.char_index = 0
        self.last_char_time = pygame.time.get_ticks()
        self.pause_start = 0
        self.finished = False

    def draw(self, screen, x, y):
        now = pygame.time.get_ticks()
        LINE_SPACING = 22 
        
        # Determine Text Color (Check for ERROR)
        current_full_text = self.text_list[self.line_index]
        text_color = (255, 0, 0) if "ERROR" in current_full_text else (0, 0, 0)
        
        # 1. ALWAYS DRAW THE BUBBLE
        bubble_rect = pygame.Rect(x + 140, y - 60, 260, 100)
        pygame.draw.rect(screen, (255, 255, 255), bubble_rect, border_radius=10)
        pygame.draw.polygon(screen, (255, 255, 255), [(x+140, y-10), (x+120, y+5), (x+140, y+20)])

        # 2. UPDATE LOGIC 
        if not self.finished:
            full_text = self.text_list[self.line_index]
            if now - self.last_char_time > 60 and self.char_index < len(full_text):
                self.char_index += 1
                self.last_char_time = now
                if self.line_index >= 4:
                    flowey_bytes2.play()
                else:
                    flowey_bytes.play()
              
            
            # Pacing Logic
            if self.char_index >= len(full_text):
                if self.pause_start == 0: self.pause_start = now
                if now - self.pause_start > 1600:
                    if self.line_index < len(self.text_list) - 1:
                        self.line_index += 1
                        self.char_index = 0
                        self.pause_start = 0
                    else:
                        self.finished = True

        # 3. DRAWING LOGIC 
        full_text = self.text_list[self.line_index]
        if "\n" in full_text:
            line1_full, line2_full = full_text.split("\n", 1)
            split_point = len(line1_full)
        else:
            line1_full, line2_full, split_point = full_text, "", 999 

        # Line 1 
        l1_to_draw = line1_full[:self.char_index]
        t1_surf = self.font.render(l1_to_draw, True, text_color)
        s1_surf = pygame.transform.scale(t1_surf, (int(t1_surf.get_width() * 0.7), int(t1_surf.get_height() * 0.7)))
        screen.blit(s1_surf, (x + 155, y - 45))

        # Line 2 
        if self.char_index > split_point:
            l2_to_draw = line2_full[:max(0, self.char_index - split_point - 1)]
            t2_surf = self.font.render(l2_to_draw, True, text_color)
            s2_surf = pygame.transform.scale(t2_surf, (int(t2_surf.get_width() * 0.7), int(t2_surf.get_height() * 0.7)))
            screen.blit(s2_surf, (x + 155, y - 45 + LINE_SPACING))
class KnightSlash:
    def __init__(self, start_x, start_y, difficulty_mode="normal"):
        self.x, self.y = start_x, start_y
        self.angle = 0
        self.timer = 0
        self.state = "tracking"
        self.line_count = 3
        self.is_finished = False

        # --- DIFFICULTY ADJUSTMENTS ---
        if difficulty_mode == "hard":
            self.tracking_speed = 0.10  # Faster tracking (was 0.05)
            self.spin_speed = 0.07      # Faster rotation (was 0.04)
            self.line_width = 4         # Wider base lines (was 2)
            self.strike_width = 20      # Thicker strike (was 12)
            self.duration = 1400        # Faster overall attack (was 2000ms)
            self.lock_time = 800        # Locks in sooner (was 1200ms)
        else:
            self.tracking_speed = 0.05
            self.spin_speed = 0.04
            self.line_width = 2
            self.strike_width = 12
            self.duration = 2000
            self.lock_time = 1200

    def update(self, player_rect):
        self.timer += 16 
        
        # 1. TRACKING PHASE
        if self.timer < self.lock_time:
            # Uses tracking_speed and spin_speed variables
            self.x += (player_rect.centerx - self.x) * self.tracking_speed
            self.y += (player_rect.centery - self.y) * self.tracking_speed
            self.angle += self.spin_speed
            self.state = "tracking"
            
        # 2. LOCK-IN PHASE
        elif self.timer < self.duration - 300: 
            self.state = "locked"
            
        # 3. STRIKE PHASE
        elif self.timer < self.duration:
            if self.state != "strike": # Play sound once
                slice.play()
            self.state = "strike"
        else:
            self.is_finished = True

    def draw(self, screen):
        if self.state == "tracking":
            color = (200, 0, 0)
            width = self.line_width
        elif self.state == "locked":
            color = (255, 0, 0)
            width = self.line_width * 2 # Double the base width for warning
        else: # STRIKE
            cable_color = (30, 30, 30)
            core_color = (200, 200, 220)
            for i in range(self.line_count):
                curr_angle = self.angle + (i * math.pi / self.line_count)
                s_x = self.x + math.cos(curr_angle) * 1000
                s_y = self.y + math.sin(curr_angle) * 1000
                e_x = self.x - math.cos(curr_angle) * 1000
                e_y = self.y - math.sin(curr_angle) * 1000
                
                # Uses self.strike_width
                pygame.draw.line(screen, cable_color, (s_x, s_y), (e_x, e_y), self.strike_width)
                pygame.draw.line(screen, core_color, (s_x, s_y), (e_x, e_y), self.strike_width // 3)
            return

        # Draw tracking/locked lines
        for i in range(self.line_count):
            curr_angle = self.angle + (i * math.pi / self.line_count)
            s_x = self.x + math.cos(curr_angle) * 1000
            s_y = self.y + math.sin(curr_angle) * 1000
            e_x = self.x - math.cos(curr_angle) * 1000
            e_y = self.y - math.sin(curr_angle) * 1000
            pygame.draw.line(screen, color, (s_x, s_y), (e_x, e_y), width)
class SupportSoul:
    def __init__(self, color_index):
        # Index 0=Cyan, 1=Orange, etc.
        # We pull directly from your pre-generated soul_sprites list
        self.image = soul_sprites[color_index]
        self.pos = [screenWidth // 2 - 16, -50] 
        self.target_y = 270
        self.has_healed = False # To ensure it only gives ONE item
        self.has_attacked = False
    def tint_soul(self, base, color):
        colored = base.copy()
        color_surf = pygame.Surface(colored.get_size()).convert_alpha()
        color_surf.fill(color)
        colored.blit(color_surf, (0, 0), special_flags=pygame.BLEND_RGBA_MULT)
        return colored

    def update(self, screen):
        global flowey_hp, boss_hp_timer, boss_shake_timer, slash_frame
        # Slide down
        if self.pos[1] < self.target_y:
            self.pos[1] += 2
        
        # Draw the soul correctly using its (x, y) list
        
        screen.blit(self.image, self.pos)
        
        # spawn a healing item once it reaches its position
        if self.pos[1] >= self.target_y:
            if not self.has_healed:
                spawn_patience_heal(self.pos)
                self.has_healed = True
            
            if not self.has_attacked:
                slash_frame = 1
                atk.play()
                self.has_attacked = True
class DamageNumber:
    def __init__(self, amount):
        self.amount = str(amount)
        self.x = screenWidth // 2
        self.display_font = titleFont 
        self.y = 100  # Will be adjusted in draw to sit OVER the bar
        self.timer = 100 

    def draw(self, screen):
        # Render the text surface to get dimensions for centering
        # Main text (Black)
        main_surf = self.display_font.render(self.amount, False, (0, 0, 0))
        # Outline (Red)
        outline_surf = self.display_font.render(self.amount, False, (255, 0, 0))
        
        # Get rect for centering
        rect = main_surf.get_rect(center=(self.x, self.y))

        # 1. Draw Red Outline (offset for thickness)
        for dx, dy in [(-3, -3), (3, -3), (-3, 3), (3, 3), (0, -3), (0, 3), (-3, 0), (3, 0)]:
            screen.blit(outline_surf, (rect.x + dx, rect.y + dy))
        
        # 2. Draw Black Main Text
        screen.blit(main_surf, rect)
        
        self.y -= 0.2
        self.timer -= 1


