def decode_image(b64_string):
    # 2. Decode the string back into raw bytes
    img_bytes = base64.b64decode(b64_string)
    
    # 3. Use BytesIO to make it act like a file in memory
    buf = io.BytesIO(base64.b64decode(b64_string))
     # 4. Load it into Pygame and return the surface
    return pygame.image.load(buf).convert_alpha()

def get_colored_soul(base_image, color):
    colored_soul = base_image.copy()
    # Create a surface of the same size and fill it with our target color
    color_surf = pygame.Surface(colored_soul.get_size()).convert_alpha()
    color_surf.fill(color)
    # Multiply the color onto the white heart
    colored_soul.blit(color_surf, (0, 0), special_flags=pygame.BLEND_RGBA_MULT)
    return colored_soul

