def draw_player_shatter(screen, elapsed_ms):
    global death_fragments
    heart_center = (player.x + 10, player.y + 10)

    # PHASE 1: Normal Heart (0.0s - 1.0s)
    if elapsed_ms < 1000:
        player.draw(screen) 

    # PHASE 2: Cracked Heart (1.0s - 1.5s) - Matches your 1s mark
    elif elapsed_ms < 2000:
        player.draw(screen)
        if player.is_invincible == True:

            player.is_invincible = False
        # X+16 is the horizontal center; Y is the top, Y+36 is the bottom.
        crack_points = [
            (player.x + 16, player.y),      # Top Center 'V'
            (player.x + 22, player.y + 8),  # Deep jag right
            (player.x + 10, player.y + 16), # Deep jag left (Center of heart)
            (player.x + 20, player.y + 24), # Jag right again
            (player.x + 16, player.y + 32)  # Bottom Center tip
        ]
        
        # Draw the line thick enough (width=3) to really see the 'split'
        pygame.draw.lines(screen, (0, 0, 0), False, crack_points, 4)
        
    # PHASE 3: Shatter & Fly Away (1.5s - 3.0s) - Finishes at 3s
    else:
        if not death_fragments:
            # Create shards only once
            for _ in range(6): # 6 shards is more accurate to the original
                death_fragments.append(HeartFragment(heart_center[0], heart_center[1]))
        
        for frag in death_fragments:
            frag.update()
            frag.draw(screen)
