def draw_pipes(screen, face_x, face_y, f_width):
    PIPE_COLOR = (30, 30, 30)
    SHINE_COLOR = (50, 50, 50)
    
    # Anchor points at the top corners
    anchors = [(-50, 80), (screenWidth + 50, 80)] 
    connections = [(face_x + 30, face_y + 60), (face_x + f_width - 30, face_y + 60)]

    for i in range(2):
        # Draw the main "thick" pipe (80px wide)
        pygame.draw.line(screen, PIPE_COLOR, anchors[i], connections[i], 80)
        
        # Draw the highlight slightly offset
        # Note: If the line is diagonal, we offset both x and y slightly
        s_offset = (anchors[i][0], anchors[i][1] + 10)
        e_offset = (connections[i][0], connections[i][1] + 10)
        pygame.draw.line(screen, SHINE_COLOR, s_offset, e_offset, 20)

def draw_pistons(screen, rect):
    # 1. OUTER CASING (Thick Black/Dark Grey)
    outline_rect = rect.inflate(6, 0)
    pygame.draw.rect(screen, (20, 20, 20), outline_rect) 

    # 2. MAIN BEAM (Industrial Grey)
    pygame.draw.rect(screen, (80, 80, 90), rect)
    
    # 3. CAUTION STRIPES (Yellow highlights)
    stripe_width = 10
    for i in range(0, rect.height, stripe_width * 2):
        stripe_points = [
            (rect.left, rect.top + i),
            (rect.right, rect.top + i + stripe_width),
            (rect.right, rect.top + i + (stripe_width * 2)),
            (rect.left, rect.top + i + stripe_width)
        ]
        # Only draw if within bounds of the piston
        pygame.draw.polygon(screen, (200, 170, 0), stripe_points)

    # 4. BOLTS/RIVETS (Replacing Thorns)
    # Circular metallic dots along the edges
    for i in range(5, rect.height, 30):
        # Left Bolt
        pygame.draw.circle(screen, (40, 40, 40), (rect.left + 5, rect.top + i), 4)
        pygame.draw.circle(screen, (150, 150, 150), (rect.left + 5, rect.top + i), 2)
        # Right Bolt
        pygame.draw.circle(screen, (40, 40, 40), (rect.right - 5, rect.top + i), 4)
        pygame.draw.circle(screen, (150, 150, 150), (rect.right - 5, rect.top + i), 2)

    # 5. HYDRAULIC GLOW (Center line)
    # A flickering red or cyan line to show it's "powered"
    glow_color = (255, 50, 50) if (pygame.time.get_ticks() // 100) % 2 == 0 else (100, 0, 0)
    pygame.draw.line(screen, glow_color, (rect.centerx, rect.top), (rect.centerx, rect.bottom), 2)

def draw_piston_warnings(screen, x, width, elapsed):
    # 1. The Red "Zone"
    # We make it flicker faster as it gets closer to 1 second
    alpha = 100 if (elapsed // 50) % 2 == 0 else 40 
    
    warning_surf = pygame.Surface((width, BORDER_HEIGHT), pygame.SRCALPHA)
    warning_surf.fill((255, 0, 0, alpha)) 
    screen.blit(warning_surf, (x, BORDER_TOP))
    
    # 2. The Outline
    pygame.draw.rect(screen, (255, 0, 0), (x, BORDER_TOP, width, BORDER_HEIGHT), 3)

def get_safe_piston_x():
    v_width = 60
    buffer = -10 
    max_attempts = 15
    
    # Calculate the actual Right Edge coordinate
    # (Starting X + Total Width)
    border_right_edge = BORDER_LEFT + BORDER_WIDTH 

    for _ in range(max_attempts):
        # Pick a spot between the Left Edge and the Right Edge
        test_x = random.randint(BORDER_LEFT + 30, border_right_edge - 30)
        
        is_safe = True
        for (w_x, w_time) in piston_warnings:
            if w_x is not None: # Safety check
                if abs(test_x - w_x) < (v_width + buffer):
                    is_safe = False
                    break
        
        if is_safe:
            return test_x
            
    return None 

def spawn_piston_attack(screen):
    current_time = pygame.time.get_ticks()
    v_width = 60 # Wider is better for warnings
    
    for warning in piston_warnings[:]:
        target_x, start_time = warning
        elapsed = current_time - start_time
        
        # 1. THE WARNING PHASE (Lasts 1000ms / 1 second)
        if elapsed < 1000:
            # Drawing happens EVERY frame now because this is called in the main loop
            # Faster flicker as it gets closer to spawning
            flicker_speed = 100 if elapsed < 700 else 50
            if (elapsed // flicker_speed) % 2 == 0:
                draw_piston_warnings(screen, target_x - (v_width // 2), v_width, elapsed)
        
        # 2. THE SPAWN PHASE (Exactly at 1 second)
        else:
            v_height = 500
            new_piston = {
                "rect": pygame.Rect(target_x - (v_width // 2), BORDER_TOP - v_height, v_width, v_height),
                "type": "piston",
                "speed": 45,        # Fast punch!
                "real_y": float(BORDER_TOP - v_height),
                "state": "striking"
            }
            left_right_bullets.append(new_piston)
            impact.play() # Play the slam sound!
            
            # Remove the warning so we stop drawing/checking it
            piston_warnings.remove(warning)
