def draw_shuriken(screen, rect):
    # Draw two lines to make an 'X'
    color = (255, 255, 255) # White shuriken
    # Top-left to bottom-right
    pygame.draw.line(screen, color, (rect.left, rect.top), (rect.right, rect.bottom), 4)
    # Top-right to bottom-left
    pygame.draw.line(screen, color, (rect.right, rect.top), (rect.left, rect.bottom), 3)

def spawn_shuriken_trio():
    global last_shuriken_time
    current_time = pygame.time.get_ticks()
    
    # 1 second between bursts
    if current_time - last_shuriken_time > 700: 
        snd_noise.play()
        side = random.randint(0, 2) # 0 = Left, 1 = Right, 2 = Top
        offset = 200 #higher makes them spawn further away
        if side == 0: # LEFT
            sx = BORDER_LEFT - offset
            sy = random.randint(BORDER_TOP, BORDER_TOP + BORDER_HEIGHT)
        elif side == 1: # RIGHT
            sx = (BORDER_LEFT + BORDER_WIDTH + offset)
            sy = random.randint(BORDER_TOP + 100, BORDER_TOP + BORDER_HEIGHT - 100)
        else: # TOP
            sx = random.randint(BORDER_LEFT, BORDER_LEFT + BORDER_WIDTH)
            sy = BORDER_TOP - offset
        
        # Get player's current center using .rect
        target_x = player.rect.centerx
        target_y = player.rect.centery
        
        # Calculate angle to the player
        dx = target_x - sx
        dy = target_y - sy
        base_angle = math.atan2(dy, dx)
        
        # Fire 3 shurikens in a fan shape
        speed = 12
        spread = 0.4 # Radians (approx 17 degrees)
        
        for offset in [-spread, 0, spread]:
            angle = base_angle + offset
            vx = math.cos(angle) * speed
            vy = math.sin(angle) * speed
            
            new_shuriken = {
                "rect": pygame.Rect(sx, sy, 20, 20),
                "vx": vx,
                "vy": vy,
                "real_x": float(sx),
                "real_y": float(sy),
                "type": "shuriken",
                "friction": 0.98 # Each shuriken loses 3% speed per frame
            }
            left_right_bullets.append(new_shuriken)
            
        last_shuriken_time = current_time
