def spawn_button_slam():
    global last_slam_time, slam_start_time, shake_timer, shake_intensity
    current_time = pygame.time.get_ticks()
    
    # 1. Trigger the Visuals (Arms and Beams)
    if current_time - last_slam_time > 1500: # Every 2.5 seconds
        slam_start_time = current_time
        last_slam_time = current_time
        # snd_slam_prepare.play() # Optional: add a "charge up" sound

    # 2. Spawn the Hitbox (Exactly when the hands hit the "table")
    slam_elapsed = current_time - slam_start_time
    

    if 300 <= slam_elapsed <= 320:
        screen_shake.play() 
        # 1. TRIGGER SCREEN SHAKE (Duration in frames, Intensity in pixels)
        shake_timer = 15 
        shake_intensity = 10
        # Create shockwaves from both sides where the hands land
        # Hand 1 (Left) and Hand 2 (Right)
        hand_x_positions = [face_x - 150, face_x + f_width + 150]
        spawn_y = random.randint(BORDER_TOP, BORDER_TOP + BORDER_HEIGHT - 60)
        for hx in hand_x_positions:

            for direction in [-1, 1]: 
                new_wave = {
                    "rect": pygame.Rect(hx, spawn_y, 35, 60), 
                    "vx": direction * 0.05, 
                    "max_v": 18,           
                    "accel": 1.15,         
                    "real_x": float(hx),
                    "real_y": float(spawn_y),
                    "type": "shockwave",
                    "color": (100, 255, 90) 
                }
                left_right_bullets.append(new_wave)
healing_pellets = []

def spawn_patience_heal(soul_pos):
    # soul_pos is [x, y]
    sx, sy = soul_pos[0], soul_pos[1]
    
    # Very slow drift speed
    speed = 1.0 
    
    pellet = {
        "pos": [float(sx), float(sy)],
        "vel": [0, speed], # Only drifts downward
        "rect": pygame.Rect(sx, sy, 120, 70), # Even bigger for that "game" feel
        "type": "bandage"
    }
    healing_pellets.append(pellet)

def update_healing_items():
    global health
    for p in healing_pellets[:]:
        p["pos"][0] += p["vel"][0]
        p["pos"][1] += p["vel"][1]
        p["rect"].topleft = (int(p["pos"][0]), int(p["pos"][1]))
        
        # --- TRUE UNDERTALE BANDAGE STYLE ---
        r = p["rect"]
        # 1. Main Bandage Body (Bright Green)
        pygame.draw.rect(screen, (0, 255, 0), r, border_radius=10)
        
        # 2. The Middle Pad (Slightly Darker Green)
        # Inflate negative to make it smaller than the main body
        pad = r.inflate(-30, -5) # pad
        pygame.draw.rect(screen, (0, 200, 0), pad, border_radius=5)
        
        # 3. The "Air Holes" (Classic 4-dot pattern on the pad)
        dot_color = (0, 100, 0)
        dots = [
            (pad.centerx - 8, pad.centery - 6), (pad.centerx + 8, pad.centery - 6),
            (pad.centerx - 8, pad.centery + 6), (pad.centerx + 8, pad.centery + 6)
        ]
        for pos in dots:
            pygame.draw.circle(screen, dot_color, pos, 3)
        # ------------------------------------

        if player.rect.colliderect(r):
            health = min(health + 20, max_health)
            healing_pellets.remove(p)
            print("RECOVERED")
            snd_heal.play()
        elif not screen.get_rect().colliderect(r):
            healing_pellets.remove(p)
def update_boss_patterns():
    global current_phase, last_piston_time, soul_positions, active_support_soul, demo_is_over, final_dialogue, intro_ms, last_slash_time
    elapsed_time = (pygame.time.get_ticks() - fight_start_time) // 1000 #time since fight started
# 1: Intro (0-23 seconds) 
    if 0 <= elapsed_time < 23:
        current_phase = 1
        cx, cy = player.rect.centerx, player.rect.centery
        soul_positions = []
        intro_ms = pygame.time.get_ticks() - fight_start_time
        t_sec = intro_ms / 1000.0
        mode = "hard" if difficulty_mode == "hard" else "normal"
        if current_phase == 1:
            cx, cy = player.rect.centerx, player.rect.centery
            
            # 1. Determine Radius
            if t_sec < 22.0:
                # Standard inward circle
                radius = max(140, 320 - (t_sec * 9))
            else:
                # THE FIX: Force the radius to grow based on real time
                # This keeps growing even if the phase logic is about to flip
                fly_off_t = t_sec - 22.0
                radius = 140 + (2500 * (fly_off_t ** 2)) # 2500 for high speed

            # 2. Update soul_positions list
            soul_positions.clear() 
            for i in range(6):
                # Use ticks for rotation so it never stops
                angle = (pygame.time.get_ticks() * 0.002) + (i * (math.pi * 2 / 6))
                sx = cx + math.cos(angle) * radius - 16
                sy = cy + math.sin(angle) * radius - 16
                soul_positions.append((sx, sy))
    if difficulty_mode == "hard":
        if 25 <= elapsed_time < 50 or 85 <= elapsed_time < 105: 
            spawn_shuriken_trio() 
            current_phase = 2
        if 28 <= elapsed_time < 55 or 90 <= elapsed_time < 105: #PISTON
            current_time = pygame.time.get_ticks()
            if current_time - last_piston_time > 2500: #Change the time between attacks
                for _ in range(3):
                    target_x = get_safe_piston_x()
        
                    # ONLY append if we actually found a spot!
                    if target_x is not None:
                        piston_warnings.append([target_x, current_time])
                        snd_b.set_volume(0.4)
                        snd_b.play()
                    else:
                        print("too crowded! Skipping one.")
            last_piston_time = current_time
        if 80 <= elapsed_time < 86:
            if active_support_soul is None:
                # Pass 0 for Cyan, and your base soul surface variable
                active_support_soul = SupportSoul(0) 
                glitch_sound.set_volume(1)
                glitch_sound.play()
            active_support_soul.update(screen)
        else:
            # If time is up, make the soul fly away
            if active_support_soul:
                active_support_soul.pos[1] -= 5
                screen.blit(active_support_soul.image, active_support_soul.pos)
                if active_support_soul.pos[1] < -60:
                    active_support_soul = None
        if 50 <= elapsed_time < 80 or 25 <= elapsed_time <27 or elapsed_time == 100:
            spawn_button_slam()
            current_phase = 3
        if 30 <= elapsed_time < 105:
            current_phase = 4
            current_time = pygame.time.get_ticks()
            mode = "hard" if difficulty_mode == "hard" else "normal"
            # Spawn a new slash every 3 seconds
            global last_slash_time 
            if current_time - last_slash_time > 3000:
                # Spawn at the player's current position to start the chase
                active_slashes.append(KnightSlash(player.rect.centerx, player.rect.centery, mode))
                last_slash_time = current_time
        if elapsed_time >= 110: demo_is_over = True
    else:
        # Attack 2: shurikens
        if 27 <= elapsed_time < 30 or 50 <= elapsed_time < 70 : 
            spawn_shuriken_trio() #=unused= spawn_bullets() 
            if current_phase != 2:
                    
                    current_phase = 2
                
        # Attack 3: The piston Strike 
        if 24 <= elapsed_time < 25 or 30 <= elapsed_time < 40:
            current_time = pygame.time.get_ticks()
            if current_time - last_piston_time > 2500: #Change the time between attacks
                for _ in range(3):
                    target_x = get_safe_piston_x()
        
                    # ONLY append if we actually found a spot!
                    if target_x is not None:
                        piston_warnings.append([target_x, current_time])
                        snd_b.set_volume(0.4)
                        snd_b.play()
                    else:
                        print("too crowded! Skipping one.")
                last_piston_time = current_time
        
        # Phase: CYAN SOUL INTERVENTION (Starts at 50 seconds)
        if 50 <= elapsed_time < 56:
            if active_support_soul is None:
                # Pass 0 for Cyan, and your base soul surface variable
                active_support_soul = SupportSoul(0) 
                glitch_sound.set_volume(1)
                glitch_sound.play()
            active_support_soul.update(screen)
        else:
            # If time is up, make the soul fly away
            if active_support_soul:
                active_support_soul.pos[1] -= 5
                screen.blit(active_support_soul.image, active_support_soul.pos)
                if active_support_soul.pos[1] < -60:
                    active_support_soul = None
        # Attack 4 Slam wave
        if 30 <= elapsed_time < 50:
            spawn_button_slam() # This handles its own timing internally
            if current_phase != 3:
                current_phase = 3
        # Attack 4, Slash
        if 24 <= elapsed_time < 25 or 40 <= elapsed_time < 70:
            current_phase = 4
            current_time = pygame.time.get_ticks()
            
            # Spawn a new slash every 3 seconds
             
            if current_time - last_slash_time > 3000:
                # Spawn at the player's current position to start the chase
                active_slashes.append(KnightSlash(player.rect.centerx, player.rect.centery))
                last_slash_time = current_time
        if elapsed_time == 74:
            pygame.mixer.stop()
            #demo_is_over = True
        
    
    if demo_is_over == True:
        if final_dialogue is None:
            msg_lines = [
                "Wait... \nWhat's happening?!",            
                "My attacks... they're \njust... STOPPING?", 
                "Wh-where's my next move?", 
                "......",
                "...........",                                  
                "Heh.",
                "Hehehe...", #unused \n YOU IDIOT
                "DID YOU REALLY THINK...\nTHAT I'M OUT OF ATTACKS?",              
                "NO...MY SPECIAL ATTACK",
                "IT'LL KEEP YOU FOR \nA WHILE."
                "IT'S CALLED...",
                "ERROR: DEMO END",              
            ]
            final_dialogue = BossDialogue(msg_lines, ui_font)
                
            return
def draw_flowey_face(screen, current_img, ox=0, oy=0, is_finale=False):
    # Position remains identical because the images are now the same size
    face_x = (screenWidth // 2 - current_img.get_width() // 2) + ox
    face_y = 20 + oy
    
    ticks = pygame.time.get_ticks()
    
    # 1. Draw whichever full TV image we passed in (Normal or Grinning)
    screen.blit(current_img, (face_x, face_y))

    # 2. Only layer the old eyes/mouth if NOT in the finale
    if not is_finale:
        eye_wobble = 2 * math.sin(ticks * 0.002)
        mouth_wobble = 3 * math.sin(ticks * 0.002)
        screen.blit(left_eye_sub, (face_x + left_eye_rect.x, face_y + left_eye_rect.y + eye_wobble))
        screen.blit(right_eye_sub, (face_x + right_eye_rect.x, face_y + right_eye_rect.y + eye_wobble))
        screen.blit(mouth_sub, (face_x + mouth_rect.x, face_y + mouth_rect.y + mouth_wobble))

    # --- SHARED EFFECTS (Hit Glow & Scanlines) ---
    if boss_shake_timer > 0:
        glow_surf = pygame.Surface(flowey_face1.get_size()).convert_alpha()
        alpha = min(150, boss_shake_timer * 5) 
        glow_surf.fill((255, 0, 0, alpha))
        screen.blit(glow_surf, (face_x, face_y), special_flags=pygame.BLEND_RGB_ADD)

    if random.randint(1, 100) <= 10:
        for _ in range(3):
            line_y = face_y + random.randint(0, flowey_face1.get_height())
            pygame.draw.line(screen, (150, 150, 150), (face_x, line_y), (face_x + flowey_face1.get_width(), line_y), 1)

def draw_industrial_beams(screen, face_x, face_y, f_width, f_height):
    BASE_METAL = (30, 30, 35)
    GLOW_GREEN = (0, 255, 50)
    
   # CALCULATE SLAM DIP
    slam_elapsed = pygame.time.get_ticks() - slam_start_time
    slam_dip = 0
    if slam_elapsed < 500: # The dip lasts half a second
        # Dramatic downward spike that settles back up
        slam_dip = math.sin((slam_elapsed / 500) * math.pi) * 50 

    beam_y = face_y + f_height // 2 + 20
    
    for side in ["left", "right"]:
        points = []
        start_x = -50 if side == "left" else screenWidth + 50
        end_x = face_x if side == "left" else face_x + f_width
        
        for i in range(11):
            t = i / 10
            curr_x = start_x + (end_x - start_x) * t
            # Add slam_dip to the existing droop
            droop = (math.sin(t * math.pi) * 30) + (slam_dip * t) 
            points.append((curr_x, beam_y + droop))
            
        # Draw thick industrial pipe
        pygame.draw.lines(screen, (20, 20, 20), False, points, 85)
        pygame.draw.lines(screen, (30, 30, 35), False, points, 75)
        pygame.draw.lines(screen, (20, 20, 20), False, points, 85) # Outer
        pygame.draw.lines(screen, BASE_METAL, False, points, 75)    # Inner
        pygame.draw.lines(screen, GLOW_GREEN, False, points, 5)     # LED strip
def draw_robotic_arms(screen, face_x, face_y, f_width, f_height):
    ARM_COLOR, JOINT_COLOR = (35, 35, 35), (55, 55, 55)
    LED_COLOR = (0, 255, 0)
    
    ticks = pygame.time.get_ticks()
    # A slower, heavier bobbing for the hands
    hand_y_offset = math.sin(ticks * 0.001) * 15
    
    # CALCULATE PUNCH OFFSET
    slam_elapsed = pygame.time.get_ticks() - slam_start_time
    punch_y = 0
    if slam_elapsed < 300: # Fast downward punch
        punch_y = (slam_elapsed / 300) * 400 # Drop 400 pixels fast!
    elif slam_elapsed < 800: # Slower recoil
        punch_y = 400 - ((slam_elapsed - 300) / 500) * 400

    # 1. THE ANCHORS (Bolted to the beams)
    # We want these to start further out to give room for the "C"
    arm_starts = [
        (face_x - 150, face_y + f_height // 2 + 30 + 50),  #to move it outward, 
        (face_x + f_width + 150, face_y + f_height // 2 + 50)
    ]
    
    # 2. THE TARGETS (Where the hands want to be)
    arm_targets = [
        (face_x - 150, face_y + f_height + 180 + hand_y_offset + punch_y),
        (face_x + f_width + 150, face_y + f_height + 180 + hand_y_offset + punch_y)
    ]

    for i in range(2):
        start, end = arm_starts[i], arm_targets[i]
        side_mult = -1 if i == 0 else 1
        segments = 18 # Higher count = smoother "C"
        
        # This is the "Elbow" or Peak of the C-curve
        # It pushes the arm OUTWARD horizontally and DOWN vertically
        elbow_x = start[0] + (150 * side_mult) 
        elbow_y = start[1] + 120 + (punch_y * 0.5)

        points = []
        for s in range(segments + 1):
            t = s / segments
            # QUADRATIC BEZIER MATH: This creates a perfect "C" or "Hook" shape
            # (1-t)^2 * start + 2(1-t)t * elbow + t^2 * end
            seg_x = (1-t)**2 * start[0] + 2*(1-t)*t * elbow_x + t**2 * end[0]
            seg_y = (1-t)**2 * start[1] + 2*(1-t)*t * elbow_y + t**2 * end[1]
            
            points.append((seg_x, seg_y))
            # Draw circles closer together so they look like one ribbed pipe
            pygame.draw.circle(screen, ARM_COLOR, (int(seg_x), int(seg_y)), 45)
            pygame.draw.circle(screen, JOINT_COLOR, (int(seg_x), int(seg_y)), 45, 2)

        # --- THE "SMOOTH" HAND ROTATION ---
        # We find the angle between the last two segments
        p1, p2 = points[-2], points[-1]
        hx, hy = p2
        
        # Calculate the angle of the arm's tip
        arm_angle = math.atan2(p2[1] - p1[1], p2[0] - p1[0])
        
        # FLIP: We subtract pi/2 (90 deg) instead of adding to flip the hand 180 degrees
        # and make it point "outward" from the arm trajectory
        palm_tilt = arm_angle - math.pi/2 

        def rot_pt(px, py):
            s, c = math.sin(palm_tilt), math.cos(palm_tilt)
            return (hx + (px-hx)*c - (py-hy)*s, hy + (px-hx)*s + (py-hy)*c)

        # --- THE PALM ---
        # We define the palm so hx, hy is the 'top' (the wrist)
        # and it grows downward (locally) into the hand
        palm_pts = [
            rot_pt(hx-60, hy),      # Top Left (at wrist)
            rot_pt(hx+60, hy),      # Top Right (at wrist)
            rot_pt(hx+65, hy+100),  # Bottom Right
            rot_pt(hx-65, hy+100)   # Bottom Left
        ]
        pygame.draw.polygon(screen, (40, 40, 40), palm_pts)
        pygame.draw.polygon(screen, (20, 20, 20), palm_pts, 2) 

        # --- THE CLAWS (Aiming at the center) ---
        for c in range(3):
            # Fingers spread across the bottom edge (hy + 100)
            fx = hx + (c - 1) * 45
            fy = hy + 100
            
            # The inward reach: 
            # If left arm (i=0), reach right (+)
            # If right arm (i=1), reach left (-)
            reach_dir = 1 if i == 0 else -1
            inward_reach = 45 * reach_dir 
            
            b1 = rot_pt(fx-15, fy)
            b2 = rot_pt(fx+15, fy)
            # The tip reaches down and INWARD
            tip = rot_pt(fx + inward_reach, fy + 60)
            
            pygame.draw.polygon(screen, (70, 70, 75), [b1, b2, tip])
            pygame.draw.polygon(screen, (10, 10, 10), [b1, b2, tip], 2)

        # Green LED Joint
        pygame.draw.circle(screen, (0, 255, 0), (int(hx), int(hy)), 25)
        pygame.draw.circle(screen, (150, 255, 150), (int(hx), int(hy)), 25, 3)

def draw_monitor_glitch(screen, x, y, w, h):
    # Fill the background with dark grey noise
    screen_rect = pygame.Rect(x, y, w, h)
    pygame.draw.rect(screen, (20, 20, 20), screen_rect)
    
    # Large chunky "corrupt" bars
    for _ in range(15):
        bw = random.randint(w // 2, w)
        bh = random.randint(10, 40) # Thick chunks
        bx = x + random.randint(-20, 20)
        by = y + random.randint(0, h - bh)
        
        # Randomly choose between white, grey, or a dark "TV blue"
        color = random.choice([(200, 200, 200), (100, 100, 100), (30, 30, 60)])
        pygame.draw.rect(screen, color, (bx, by, bw, bh))

    # Add a thin "scanline" jitter over the whole screen
    if random.random() > 0.5:
        pygame.draw.line(screen, (255, 255, 255), (x, by), (x + w, by), 2)
