slash_frame = 0  # 0 = inactive, 1-15 = animating

def draw_slash_vfx(screen, target_pos):
    global slash_frame, boss_shake_timer, boss_hp_timer, flowey_hp
    
    if slash_frame > 0:
        x, y = target_pos
        
        # Define the 3 points for the "vertical bent-left" look
        # Top-right to center-left to bottom-right
        p1 = (x + 40, y - 80)  # Start (Top)
        p2 = (x - 20, y)       # Bend (Middle-Left)
        p3 = (x + 30, y + 100) # End (Bottom)

        # Draw Outline (Black, very thick)
        pygame.draw.lines(screen, (0, 0, 0), False, [p1, p2, p3], 14)
        
        # Draw the "Growing" Pink Line
        # Frame 1-7 draws first half (p1 to p2), Frame 8-15 draws second half (p2 to p3)
        pink = (255, 128, 128)
        if slash_frame <= 8:
            # Gradually move from p1 toward p2
            progress = slash_frame / 8
            current_end = (p1[0] + (p2[0] - p1[0]) * progress, p1[1] + (p2[1] - p1[1]) * progress)
            pygame.draw.line(screen, pink, p1, current_end, 7)
        else:
            # Finish first half, then grow from p2 toward p3
            progress = (slash_frame - 8) / 7
            current_end = (p2[0] + (p3[0] - p2[0]) * progress, p2[1] + (p3[1] - p2[1]) * progress)
            pygame.draw.lines(screen, pink, False, [p1, p2, current_end], 7)

        slash_frame += 1

        # --- THE TRIGGER POINT ---
        if slash_frame > 15:
            slash_frame = 0 # End animation
            
            dmg = (flowey_max_hp // 6)
            flowey_hp -= dmg
    
            active_damage.append(DamageNumber(dmg))
            boss_shake_timer = 40 
            boss_hp_timer = 120
            hurt_big.play() 
