slowerSpeed = False
running = True


waveWidth = 10
waveSpeed = 0.005
def update_bullets():
    
    
    for b in left_right_bullets[:]: # Use [:] to safely remove items while looping
        if b.get("type") == "piston":
            # 1. STRIKING: Punching down into the box
            if b["state"] == "striking":
                b["real_y"] += b["speed"]
                if b["real_y"] >= BORDER_TOP:
                    b["real_y"] = BORDER_TOP
                    b["state"] = "pausing"
                    b["timer"] = pygame.time.get_ticks()

            # 2. PAUSING: Stay still to damage the player
            elif b["state"] == "pausing":
                if pygame.time.get_ticks() - b["timer"] > 600: # Stay for 0.6 seconds
                    b["state"] = "retracting"

            # 3. RETRACTING: Snap back up quickly
            elif b["state"] == "retracting":
                b["real_y"] -= b["speed"]
                # Once it's fully back above the box, delete it
                if b["real_y"] < BORDER_TOP - b["rect"].height:
                    left_right_bullets.remove(b)
                    continue # Skip the rest of this loop for this bullet

            # Finally, update the actual rectangle position
            b["rect"].y = int(b["real_y"])
            continue
        # --- TYPE 1: SHURIKENS (Diagonal Movement) ---
        if b.get("type") == "shuriken":
            b["vx"] *= b["friction"] #for friction
            b["vy"] *= b["friction"]
            if abs(b["vx"]) < 1: b["vx"] = 1 * (1 if b["vx"] > 0 else -1)
            # Apply the diagonal velocity
            b["real_x"] += b["vx"]
            b["real_y"] += b["vy"]
            b["rect"].x = int(b["real_x"])
            b["rect"].y = int(b["real_y"])
            if b["rect"].top > screenHeight or b["rect"].bottom < 0:
                left_right_bullets.remove(b)
        if b["type"] == "shockwave":
            # Acceleration: Increase vx by 0.5 every frame until it hits max speed (15)
            # We use math.copysign to keep the direction (left or right)
            if abs(b["vx"]) < b["max_v"]:
                b["vx"] *= b["accel"]
            
            b["real_x"] += b["vx"]
            b["rect"].x = int(b["real_x"])
        
        
        elif b.get("type") == "bounce": #treat it as a normal left-right bullet
            if "base_x" not in b: b["base_x"] = b["real_x"] 
            
            b["real_x"] = b["base_x"] + (waveWidth * math.sin(pygame.time.get_ticks() * waveSpeed))
            b["rect"].x = int(b["real_x"])
            
            # 2. Vertical Movement & Bouncing
            b["rect"].y += b["speed"]

            if b["rect"].bottom >= (BORDER_TOP + BORDER_HEIGHT):
                b["speed"] = -abs(b["speed"])
                b["rect"].bottom = BORDER_TOP + BORDER_HEIGHT
            elif b["rect"].top <= BORDER_TOP:
                b["speed"] = abs(b["speed"])
                b["rect"].top = BORDER_TOP
        t = pygame.time.get_ticks()
    
        wobble = waveWidth * math.sin(t * waveSpeed)
        b["rect"].x = int(b["real_x"] + wobble)
    
# ===== INPUT HANDLING =====
vel_y = 0
jump_frames = 0 

def handle_green_soul(soul_rect, current_angle):
    keys = pygame.key.get_pressed()
    dx, dy = 0, 0
    
    # Check 8 directions
    if keys[pygame.K_LEFT] or keys[pygame.K_a]: dx -= 1
    if keys[pygame.K_RIGHT] or keys[pygame.K_d]: dx += 1
    if keys[pygame.K_UP] or keys[pygame.K_w]: dy -= 1
    if keys[pygame.K_DOWN] or keys[pygame.K_s]: dy += 1

    # Only update angle if a key is pressed, otherwise stay at last angle
    if dx != 0 or dy != 0:
        # math.atan2(y, x) -> we negate dy because Pygame's Y is inverted
        target_angle = math.degrees(math.atan2(-dy, dx))
        return target_angle
    return current_angle

def draw_shield(screen, soul_rect, angle, radius=45):
    # Calculate shield position on the orbit
    rad = math.radians(angle)
    shield_x = soul_rect.centerx + radius * math.cos(rad)
    shield_y = soul_rect.centery - radius * math.sin(rad) # Subtract because Y grows downward
    
    # Draw a simple arc or line for the shield
    # For a real sprite: rotated_shield = pygame.transform.rotate(shield_surf, angle)
    pygame.draw.circle(screen, (0, 255, 0), (int(shield_x), int(shield_y)), 10)

def handleInputs_Green(x, y, border_rect):
    keys = pygame.key.get_pressed()
    
    # 1. CENTER THE SOUL (Standard for Green Mode)
    # The soul usually locks to the center of the arena
    x = border_rect.centerx - (player_image.get_width() // 2)
    y = border_rect.centery - (player_image.get_height() // 2)

    # 2. DETERMINE SHIELD ANGLE (8 Directions)
    dx, dy = 0, 0
    if keys[pygame.K_LEFT] or keys[pygame.K_a]: dx -= 1
    if keys[pygame.K_RIGHT] or keys[pygame.K_d]: dx += 1
    if keys[pygame.K_UP] or keys[pygame.K_w]: dy -= 1
    if keys[pygame.K_DOWN] or keys[pygame.K_s]: dy += 1

    # 3. CALCULATE ANGLE
    # math.atan2 returns radians. We convert to degrees for pygame.transform.rotate
    import math
    if dx != 0 or dy != 0:
        shield_angle = math.degrees(math.atan2(-dy, dx))
    else:
        # Default position (usually Up)
        shield_angle = 90 
        
    return x, y, shield_angle
def handleInputs(x, y, soul_mode="red"):
    global vel_y, jump_frames, current_shield_angle
    keys = pygame.key.get_pressed()
    move_amt = 5
    
    # 1. SIDEWAYS (Same for both)
    if keys[pygame.K_a] or keys[pygame.K_LEFT]: x -= move_amt
    if keys[pygame.K_d] or keys[pygame.K_RIGHT]: x += move_amt

    # 2. DEFINE BOUNDARIES
    pw, ph = player_image.get_width(), player_image.get_height()
    min_x, max_x = border_rect.left + 1, border_rect.right - pw - 1
    min_y, max_y = border_rect.top + 1, border_rect.bottom - ph - 1

    if soul_mode == "blue":
        gravity = 0.5
        jump_power = -5.0      # The initial "pop" off the ground
        max_jump_time = 20     # How many frames you can "boost" (try 10-20)
        hold_extra = -0.55      # Strength of the hold boost

        is_grounded = (y >= max_y)

        if is_grounded:
            y = max_y
            vel_y = 0
            if keys[pygame.K_w] or keys[pygame.K_UP]:
                vel_y = jump_power
                jump_frames = max_jump_time # Reset the "fuel" for the jump
        else:
            # VARIABLE JUMP: Only boost if holding UP and we have "fuel" left
            if (keys[pygame.K_w] or keys[pygame.K_UP]) and jump_frames > 0:
                vel_y += hold_extra
                jump_frames -= 1 # Consume fuel
            else:
                jump_frames = 0 # Stop boosting if they let go or run out
        
        vel_y += gravity
        y += vel_y
        return x, y, None
    elif soul_mode == "green":
        # Lock position to center
        x = border_rect.centerx - (pw // 2)
        y = border_rect.centery - (ph // 2)
        
        # Update the PERSISTENT angle
        current_shield_angle = handle_green_soul(pygame.Rect(x, y, pw, ph), current_shield_angle)
        
        return x, y, current_shield_angle
    else:
        # --- NORMAL FLYING ---
        if keys[pygame.K_w] or keys[pygame.K_UP]: y -= move_amt
        if keys[pygame.K_s] or keys[pygame.K_DOWN]: y += move_amt

    # 3. FINAL CLAMP (Prevents flying out of the box)
    x = max(min_x, min(x, max_x))
    y = max(min_y, min(y, max_y))
    
    return x, y
