last_glitch_se_time = 0

def draw_glitch_vfx(surface, intensity=15, elapsed_ms=0):
    global last_glitch_se_time
    
    # --- AUDIO SYNC: Play the glitch SE every 150ms during this phase ---
    if elapsed_ms - last_glitch_se_time > 150:
        thump.play()
        #glitch_sound.play() 
        last_glitch_se_time = elapsed_ms

    for _ in range(intensity):
        # 1. Select a horizontal slice
        slice_y = random.randint(0, screenHeight - 40)
        slice_h = random.randint(10, 50)
        offset_x = random.randint(-40, 40)
        
        rect = pygame.Rect(0, slice_y, screenWidth, slice_h)
        
        # 2. Grab the slice
        try:
            slice_surf = surface.subsurface(rect).copy()
            
            # 3. Apply a slight color tint (like the sepia/orange in your image)
            # This makes the 'glitched' parts stand out from the black
            if random.random() > 0.5:
                slice_surf.fill((200, 100, 50), special_flags=pygame.BLEND_MULT)
            
            # 4. Blit it back with the offset
            surface.blit(slice_surf, (offset_x, slice_y))
            
            # 5. Visual "Ghosting" - draw it again slightly offset in a different color
            if random.random() > 0.8:
                surface.blit(slice_surf, (offset_x + 5, slice_y), special_flags=pygame.BLEND_ADD)
                
        except ValueError: # Prevents crashes if the rect is slightly off-screen
            continue
