"32"
while running:
    global current_time
    current_time = pygame.time.get_ticks()
    if health <= 0:
        health = 0
        player.is_invincible = False
        play_game_over()

        continue 
    titleScreen()
    screen.fill((0, 0, 0))
    update_boss_patterns()
    update_healing_items()
    spawn_piston_attack(screen)
    update_bullets()
    for event in pygame.event.get():
        if event.type == FINALE_END_EVENT:
            if finale_step == 1:
                pause_timer = pygame.time.get_ticks() + 1900 
                finale_step = 2
                #-unused- print("Intro ended: Starting silence...")
        if event.type == pygame.QUIT:
            running = False
        elif event.type == pygame.KEYDOWN:
            if event.key == pygame.K_ESCAPE:
                running = False

            elif event.key == pygame.K_SPACE:
                slowerSpeed = not slowerSpeed
                print(f"Slow-speed {'ON' if slowerSpeed else 'OFF'}")
            skip_intro()
        elif event.type == pygame.KEYUP:
            pass  # Handle key up if needed
        elif event.type == pygame.MOUSEBUTTONDOWN:
            print(f"Mouse button {event.button} clicked at {event.pos}")
    if finale_step == 2:
        if current_time >= pause_timer:
            #-unused- print("Silence over: Playing Part 2")
            play_on_channel(1, loops=0) # Play Part 2
            part2_start_time = current_time
            finale_step = 3

    elif finale_step == 3:
        if current_time >= part2_start_time + 40400: 
            #-unused- print("Part 2 cut-off: Dropping into Part 3 Loop")
            play_on_channel(2, loops=-1) # Part 3 
            finale_step = 4
        
    #spawnBullet()
    result = handleInputs(player.x, player.y, soul_mode)
    player.x, player.y = result[0], result[1]
    if len(result) > 2:
        current_shield_angle = result[2]

    pygame.display.set_caption(f"Floweytale")
   
    # Update all bullets
    bullet_group.update()
    # Check collisions
    for b_obj in left_right_bullets: #
        if player.rect.colliderect(b_obj["rect"]): # Check if the player's rectangle collides with the rectangle of the left-right bullet
            if health > 0 and not player.is_invincible:
                print("collision detected!")
                take_damage(4)

                if player.rect.centerx < b_obj["rect"].centerx:
                    if health > 0 and not player.is_invincible:
                        player.x -= 10
                    else:
                        player.x += 10
    collided_bullets = pygame.sprite.spritecollide(player, bullet_group, False) #

    if collided_bullets:
        if health > 0 and not player.is_invincible:
            print("collision detected!")
            take_damage(3)
            if player.rect.centerx < enemy_bullet.rect.centerx:
                player.x -= 10
            else:
                player.x += 10
    offset_x, offset_y = 0, 0
    if shake_timer > 0:
        offset_x = random.randint(-shake_intensity, shake_intensity)
        offset_y = random.randint(-shake_intensity, shake_intensity)
        shake_timer -= 1 # Countdown the shake
    shaky_border = border_rect.move(offset_x, offset_y)    
    pygame.draw.rect(screen, (WHITE), shaky_border, 3) 
    
    for b_obj in left_right_bullets:
        if b_obj.get("type") == "piston":
            draw_pistons(screen, b_obj["rect"]) # Use the green spiky function
        elif b_obj.get("type") == "shuriken":
            draw_shuriken(screen, b_obj["rect"])
        elif b_obj.get("type") == "shockwave":
            # 1. Main Danger Body 
            pygame.draw.rect(screen, (100, 100, 120), b_obj["rect"]) 
            inner = b_obj["rect"].inflate(-10, -20)
            pygame.draw.rect(screen, (255, 255, 200), inner)

            line_y = b_obj["rect"].centery
            pygame.draw.line(screen, (0, 0, 0), (b_obj["rect"].left, line_y), (b_obj["rect"].right, line_y), 3)
        else:
            pygame.draw.rect(screen, (255, 0, 0), b_obj["rect"]) # Draw the falling rectangle 
    
   
    base_face_x = screenWidth // 2 - flowey_face1.get_width() // 2
    base_face_y = 20

    
    glitch_x = 0
    glitch_y = 0
    if random.randint(1, 100) <= 5:
        glitch_x = random.randint(-5, 5)
        glitch_y = random.randint(-2, 2)

    face_x = base_face_x + glitch_x
    face_y = base_face_y + glitch_y
    #=====
    for slash in active_slashes[:]: 
        slash.update(player.rect)
    
        # Check for Damage 
        if slash.state == "strike":
            for i in range(slash.line_count):
                angle = slash.angle + (i * math.pi / slash.line_count)
                s_x = slash.x + math.cos(angle) * 1000
                s_y = slash.y + math.sin(angle) * 1000
                e_x = slash.x - math.cos(angle) * 1000
                e_y = slash.y - math.sin(angle) * 1000
            
                if player.rect.clipline((s_x, s_y), (e_x, e_y)) and not player.is_invincible:
                    take_damage(5) 
                    print("SLICED!") 

        if slash.is_finished:
            active_slashes.remove(slash)

    #==SHAKE OFFSET===
    shake_x = 0
    shake_y = 0

    if boss_shake_timer > 0:
        shake_x = random.randint(-10, 10) if boss_shake_timer > 0 else 0
        shake_y = random.randint(-10, 10) if boss_shake_timer > 0 else 0    
        boss_shake_timer -= 1 # Countdown the shake duration
    shaken_face_x = face_x + shake_x
    shaken_face_y = face_y + shake_y    
    #=====    

    if current_phase == 1:
        # 1. Background
        screen.blit(flowey_face1, (face_x, face_y))
        pygame.draw.rect(screen, (0, 0, 0), (face_x + 10, face_y + 10, f_width - 20, f_height - 20))
        
        # 2. Text 
        intro_ms = pygame.time.get_ticks() - fight_start_time
        narrator.draw(screen, intro_ms)

        # 3. Glitch Trigger Logic
        if intro_ms > 22000 and not is_glitch_stunting:
            is_glitch_stunting = True
            glitch_stunt_end = pygame.time.get_ticks() + 1200
            glitch_sound.play()

        if is_glitch_stunting:
            if pygame.time.get_ticks() < glitch_stunt_end:
                draw_monitor_glitch(screen, face_x, face_y, f_width, f_height)
            else:
                current_phase = 2 # Transition to boss
                glitch_sound.stop()
        for i, pos in enumerate(soul_positions):
            screen.blit(soul_sprites[i], pos)
    else:
        draw_pipes(screen, shaken_face_x, shaken_face_y, f_width)
        draw_industrial_beams(screen, shaken_face_x, shaken_face_y, f_width, f_height)
        draw_robotic_arms(screen, shaken_face_x, shaken_face_y, f_width, f_height)
        draw_flowey_face(screen, flowey_face1, shake_x, shake_y)
    draw_flowey_hp()
    if slash_frame > 0:
        center_tv = (screenWidth // 2 + shake_x, 120 + shake_y)
        draw_slash_vfx(screen, center_tv)
    if active_support_soul is not None:
        active_support_soul.update(screen)
    for slash in active_slashes:
        slash.draw(screen)
    now = pygame.time.get_ticks()
    player.updateInvis()
    # Draw Player (Flash logic)
    draw_player = True
    if player.is_invincible:
        if (now // 100) % 2 == 0:
            draw_player = False

    if draw_player:
        player.draw(screen)
        # DRAW GREEN SHIELD HERE
        if soul_mode == "green":
            draw_shield(screen, player.rect, current_shield_angle)
    else:
        pass
    
    drawHealth()
    if has_died and finale_step == 1:
        skip_text = ui_font.render("Press [C] to Skip", True, (255, 255, 255))
        # Position in bottom right
        screen.blit(skip_text, (screenWidth - skip_text.get_width() - 20, screenHeight - 40))
    bullet_group.draw(screen)
    if demo_is_over:
        if final_dialogue.line_index >= 4:
            draw_flowey_face(screen, flowey_face2, is_finale=True)
        final_dialogue.draw(screen, screenWidth // 2, 80)
        
        #demo complete
        if final_dialogue.finished:
            pygame.mixer.stop()
            end_msg = ui_font.render("--- DEMO COMPLETE: PRESS ESC TO QUIT ---", True, YELLOW)
            ty_msg = ui_font.render("* THANK YOU FOR PLAYING!", False, WHITE)
            screen.blit(end_msg, end_msg.get_rect(center=(400, 500)))
            screen.blit(ty_msg, ty_msg.get_rect(center=(400, 400)))
    pygame.display.flip()
    clock.tick(FPS)

   

pygame.quit()



def dropRectangle(): #cool bouncing rectangle pattern that I might use for a boss attack or something. 
    for b_obj in left_right_bullets:
        b_obj["real_x"] = b_obj.get("real_x", float(b_obj["rect"].x))
        b_obj["real_y"] = b_obj.get("real_y", float(b_obj["rect"].y))
        # 1. Initialize velocities if they don't exist (First time only)
        if "vx" not in b_obj:
            b_obj["vx"] = 4  # Initial side speed
        if "vy" not in b_obj:
            b_obj["vy"] = b_obj["speed"] # Use your existing speed for vertical

        # 2. Update the "Real" floating point positions
        b_obj["real_x"] += b_obj["vx"]
        b_obj["real_y"] += b_obj["vy"]

        # 3. Sync the Rect to the real positions
        b_obj["rect"].x = int(b_obj["real_x"])
        b_obj["rect"].y = int(b_obj["real_y"])

        # --- BOUNCE LOGIC ---

        # 4. Vertical Bounce (Top/Bottom)
        if b_obj["rect"].bottom >= (BORDER_TOP + BORDER_HEIGHT):
            b_obj["vy"] = -abs(b_obj["vy"]) # Force it to go UP
            b_obj["rect"].bottom = BORDER_TOP + BORDER_HEIGHT
        elif b_obj["rect"].top <= BORDER_TOP:
            b_obj["vy"] = abs(b_obj["vy"])  # Force it to go DOWN
            b_obj["rect"].top = BORDER_TOP

        # 5. Horizontal Bounce (Left/Right)
        # Assuming your box starts at 0 and goes to screenWidth
        if b_obj["rect"].right >= BORDER_LEFT + BORDER_WIDTH:
            b_obj["vx"] = -abs(b_obj["vx"]) # Force it to go LEFT
            b_obj["rect"].right = BORDER_LEFT + BORDER_WIDTH
        elif b_obj["rect"].left <= BORDER_LEFT:
            b_obj["vx"] = abs(b_obj["vx"])  # Force it to go RIGHT
            b_obj["rect"].left = BORDER_LEFT
            
        # Update real_x/y one last time after the "snap" back from the wall
        b_obj["real_x"] = float(b_obj["rect"].x)
        b_obj["real_y"] = float(b_obj["rect"].y)

